    }
    h1, h2, h3, h4, h5, button, select, input, textarea {
      font-family: 'Google Sans Text', sans-serif;
    }
    .font-google-sans {
      font-family: 'Google Sans', sans-serif;
    }
  </style>
  <title>Decision & Risk Log</title>
</head>
<body class="p-6 bg-white text-[#1f1f1f]">
  <div class="max-w-5xl mx-auto space-y-6">

    <!-- Add Decision & Risk Form -->
    <form id="add-form" onsubmit="addItem(event)" class="bg-[#f0f4f9] border border-[#e2e8f0] p-4 rounded-xl space-y-4">
      <div class="text-xs font-semibold text-[#5f6368] uppercase tracking-wider font-google-sans">Log New Decision / Risk</div>
      <div class="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
        <div class="md:col-span-2">
          <label class="block text-xs text-[#5f6368] mb-1 font-medium">Decision or Risk Description</label>
          <input 
            id="new-decision" 
            type="text" 
            required 
            placeholder="e.g. Approved the MDM deployment timeline" 
            class="w-full bg-white border border-[#747775] rounded-lg px-3 py-2 text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] placeholder-[#5f6368]"
          />
        </div>
        <div>
          <label class="block text-xs text-[#5f6368] mb-1 font-medium">Owner</label>
          <select 
            id="new-owner" 
            class="w-full bg-white border border-[#747775] rounded-lg px-3 py-2 text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] cursor-pointer"
          >
            <!-- Dynamically Populated -->
          </select>
        </div>
        <div class="grid grid-cols-2 gap-2">
          <div>
            <label class="block text-xs text-[#5f6368] mb-1 font-medium">Status</label>
            <select 
              id="new-status" 
              class="w-full bg-white border border-[#747775] rounded-lg px-2 py-2 text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] cursor-pointer"
            >
              <option value="Pending">Pending</option>
              <option value="Decided" selected>Decided</option>
              <option value="Mitigated">Mitigated</option>
              <option value="Escalated">Escalated</option>
            </select>
          </div>
          <div>
            <label class="block text-xs text-[#5f6368] mb-1 font-medium">Impact</label>
            <select 
              id="new-impact" 
              class="w-full bg-white border border-[#747775] rounded-lg px-2 py-2 text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] cursor-pointer"
            >
              <option value="Low">Low</option>
              <option value="Medium" selected>Medium</option>
              <option value="High">High</option>
              <option value="Critical">Critical</option>
            </select>
          </div>
        </div>
      </div>
      <div class="flex justify-end">
        <button 
          type="submit" 
          class="px-4 py-2 bg-[#0b57d0] hover:bg-[#0842a0] text-white text-xs font-medium rounded-lg transition cursor-pointer font-google-sans"
        >
          Add Entry
        </button>
      </div>
    </form>

    <!-- Filters & Search -->
    <div class="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
      <div class="relative flex-1 max-w-md">
        <input 
          id="search-input" 
          type="text" 
          placeholder="Search decisions or risks..." 
          oninput="render()" 
          class="w-full bg-white border border-[#e2e8f0] rounded-lg px-3 py-1.5 text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] placeholder-[#5f6368]"
        />
      </div>
      <div class="flex items-center space-x-3">
        <select 
          id="filter-status" 
          onchange="render()" 
          class="bg-white border border-[#e2e8f0] rounded-lg px-3 py-1.5 text-xs text-[#1f1f1f] focus:outline-none cursor-pointer font-medium"
        >
          <option value="all">All Statuses</option>
          <option value="Pending">Pending</option>
          <option value="Decided">Decided</option>
          <option value="Mitigated">Mitigated</option>
          <option value="Escalated">Escalated</option>
        </select>
        <select 
          id="filter-impact" 
          onchange="render()" 
          class="bg-white border border-[#e2e8f0] rounded-lg px-3 py-1.5 text-xs text-[#1f1f1f] focus:outline-none cursor-pointer font-medium"
        >
          <option value="all">All Impacts</option>
          <option value="Low">Low</option>
          <option value="Medium">Medium</option>
          <option value="High">High</option>
          <option value="Critical">Critical</option>
        </select>
      </div>
    </div>

    <!-- Decisions & Risks Table -->
    <div class="overflow-x-auto bg-white border border-[#e2e8f0] rounded-xl">
      <table class="w-full text-left border-collapse">
        <thead>
          <tr class="bg-[#f0f4f9] border-b border-[#e2e8f0]">
            <th class="py-3 px-4 text-xs font-semibold text-[#5f6368] w-2/5 font-google-sans">Decision / Risk</th>
            <th class="py-3 px-4 text-xs font-semibold text-[#5f6368] w-1/5 font-google-sans">Owner</th>
            <th class="py-3 px-4 text-xs font-semibold text-[#5f6368] w-1/5 font-google-sans">Status</th>
            <th class="py-3 px-4 text-xs font-semibold text-[#5f6368] w-1/5 font-google-sans">Impact</th>
            <th class="py-3 px-4 text-xs font-semibold text-[#5f6368] w-[80px] text-right font-google-sans">Actions</th>
          </tr>
        </thead>
        <tbody id="log-tbody" class="divide-y divide-[#e2e8f0]">
          <!-- Interactive log entries populated dynamically -->
        </tbody>
      </table>
    </div>
  </div>

  <script>
    const envId = window.__sandboxEnvId;
    const syncKey = "decision_risk_log_state";

    // Real team members from workspace
    const TEAM_MEMBERS = [
      { name: "Sakura Okoro", email: "sakura@example.com", initials: "SO", color: "bg-[#e8f0fe] text-[#1a73e8]" },
      { name: "Malik Harold", email: "malik@example.com", initials: "MH", color: "bg-[#fce8e6] text-[#c5221f]" },
      { name: "Adam Lee", email: "adam@example.com", initials: "AL", color: "bg-[#e6f4ea] text-[#137333]" }
    ];

    // Initial default items with team member assignments
    const DEFAULT_ITEMS = [
      {
        id: "1",
        decision: "Approved MDM distribution strategy for iOS deployment with Managed Apple IDs.",
        ownerEmail: "malik@example.com",
        status: "Decided",
        impact: "High",
        timestamp: Date.now() - 86400000 * 3
      },
      {
        id: "2",
        decision: "Resolve NCCN Guidelines caching latency currently averaging 1.2s.",
        ownerEmail: "sakura@example.com",
        status: "Pending",
        impact: "Medium",
        timestamp: Date.now() - 86400000 * 2
      },
      {
        id: "3",
        decision: "HIPAA compliance sign-off on direct push notification pathway for pathology biomarker returns.",
        ownerEmail: "adam@example.com",
        status: "Mitigated",
        impact: "Critical",
        timestamp: Date.now() - 86400000
      }
    ];

    let state = {
      items: []
    };

    let isSaving = false;

    // Helper to escape HTML and prevent injection
    function escapeHtml(str) {
      if (!str) return '';
      return str
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
    }

    // Auto-adjust textarea height dynamically
    function autoResizeTextareas() {
      document.querySelectorAll('td textarea').forEach(textarea => {
        textarea.style.height = 'auto';
        textarea.style.height = textarea.scrollHeight + 'px';
      });
    }

    // Initialize dropdown choices
    function initOwnerSelects() {
      const newOwnerSelect = document.getElementById('new-owner');
      newOwnerSelect.innerHTML = TEAM_MEMBERS.map(m => `
        <option value="${m.email}">${m.name}</option>
      `).join('');
    }

    // Main Render Loop
    function render() {
      const searchTerm = document.getElementById('search-input').value.toLowerCase();
      const filterStatus = document.getElementById('filter-status').value;
      const filterImpact = document.getElementById('filter-impact').value;

      const tbody = document.getElementById('log-tbody');
      tbody.innerHTML = '';

      const filteredItems = state.items.filter(item => {
        const matchesSearch = item.decision.toLowerCase().includes(searchTerm);
        const matchesStatus = filterStatus === 'all' || item.status === filterStatus;
        const matchesImpact = filterImpact === 'all' || item.impact === filterImpact;
        return matchesSearch && matchesStatus && matchesImpact;
      });

      if (filteredItems.length === 0) {
        tbody.innerHTML = `
          <tr>
            <td colspan="5" class="py-8 text-center text-sm text-[#5f6368]">
              No decisions or risks found.
            </td>
          </tr>
        `;
        return;
      }

      // Sort with newest on top
      filteredItems.sort((a, b) => b.timestamp - a.timestamp);

      filteredItems.forEach(item => {
        const tr = document.createElement('tr');
        tr.className = "hover:bg-[#f8f9fa] border-b border-[#e2e8f0] transition-colors";

        let ownerOptions = '';
        TEAM_MEMBERS.forEach(member => {
          const selected = item.ownerEmail === member.email ? 'selected' : '';
          ownerOptions += `<option value="${member.email}" ${selected}>${member.name}</option>`;
        });

        const statuses = ["Pending", "Decided", "Mitigated", "Escalated"];
        let statusOptions = '';
        statuses.forEach(status => {
          const selected = item.status === status ? 'selected' : '';
          statusOptions += `<option value="${status}" ${selected}>${status}</option>`;
        });

        const impacts = ["Low", "Medium", "High", "Critical"];
        let impactOptions = '';
        impacts.forEach(impact => {
          const selected = item.impact === impact ? 'selected' : '';
          impactOptions += `<option value="${impact}" ${selected}>${impact}</option>`;
        });

        const activeOwner = TEAM_MEMBERS.find(m => m.email === item.ownerEmail) || TEAM_MEMBERS[0];

        tr.innerHTML = `
          <td class="py-3 px-4">
            <textarea 
              data-id="${item.id}"
              onchange="updateItemField('${item.id}', 'decision', this.value)" 
              class="w-full bg-transparent resize-none border-none focus:outline-none focus:ring-1 focus:ring-[#0b57d0] rounded p-1 text-sm text-[#1f1f1f]"
              rows="1"
            >${escapeHtml(item.decision)}</textarea>
          </td>
          <td class="py-3 px-4">
            <div class="flex items-center space-x-2">
              <div class="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${activeOwner.color}">
                ${activeOwner.initials}
              </div>
              <select 
                onchange="updateItemField('${item.id}', 'ownerEmail', this.value)" 
                class="bg-transparent border-none text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] rounded cursor-pointer py-1"
              >
                ${ownerOptions}
              </select>
            </div>
          </td>
          <td class="py-3 px-4">
            <select 
              onchange="updateItemField('${item.id}', 'status', this.value)" 
              class="bg-transparent border-none text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] rounded cursor-pointer py-1 font-medium"
            >
              ${statusOptions}
            </select>
          </td>
          <td class="py-3 px-4">
            <select 
              onchange="updateItemField('${item.id}', 'impact', this.value)" 
              class="bg-transparent border-none text-sm text-[#1f1f1f] focus:outline-none focus:ring-1 focus:ring-[#0b57d0] rounded cursor-pointer py-1 font-medium"
            >
              ${impactOptions}
            </select>
          </td>
          <td class="py-3 px-4 text-right">
            <button 
              onclick="deleteItem('${item.id}')" 
              class="text-xs text-[#5f6368] hover:text-[#d93025] font-medium transition cursor-pointer p-1 rounded hover:bg-[#f1f3f4]"
            >
              Delete
            </button>
          </td>
        `;
        tbody.appendChild(tr);
      });
    }

    // Load state from Workspace synchronization backend or local storage
    async function loadSyncedState() {
      if (!envId) {
        const local = localStorage.getItem(syncKey);
        if (local) {
          const parsed = JSON.parse(local);
          if (JSON.stringify(state) !== JSON.stringify(parsed)) {
            state = parsed;
            render();
            autoResizeTextareas();
          }
        } else {
          state = { items: DEFAULT_ITEMS };
          localStorage.setItem(syncKey, JSON.stringify(state));
          render();
          autoResizeTextareas();
        }
        return;
      }

      if (isSaving) return;

      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && json.data.items) {
          if (JSON.stringify(state) !== JSON.stringify(json.data)) {
            const activeElement = document.activeElement;
            const activeId = activeElement ? activeElement.getAttribute('data-id') : null;

            state = json.data;
            render();
            autoResizeTextareas();

            if (activeId) {
              const el = document.querySelector(`[data-id="${activeId}"]`);
              if (el) el.focus();
            }
          }
        } else {
          state = { items: DEFAULT_ITEMS };
          await saveSyncedState(state);
          render();
          autoResizeTextareas();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    // Save updated state back to synchronization endpoint
    async function saveSyncedState(newState) {
      state = newState;
      localStorage.setItem(syncKey, JSON.stringify(state));
      render();
      autoResizeTextareas();

      if (!envId) return;
      isSaving = true;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      } finally {
        isSaving = false;
      }
    }

    // Add entry helper
    function addItem(e) {
      if (e) e.preventDefault();

      const decisionInput = document.getElementById('new-decision');
      const ownerInput = document.getElementById('new-owner');
      const statusInput = document.getElementById('new-status');
      const impactInput = document.getElementById('new-impact');

      const decision = decisionInput.value.trim();
      if (!decision) return;

      const newItem = {
        id: Date.now().toString(),
        decision: decision,
        ownerEmail: ownerInput.value,
        status: statusInput.value,
        impact: impactInput.value,
        timestamp: Date.now()
      };

      const updatedItems = [newItem, ...state.items];
      saveSyncedState({ items: updatedItems });

      decisionInput.value = '';
    }

    // Update field helper
    function updateItemField(id, field, value) {
      const updatedItems = state.items.map(item => {
        if (item.id === id) {
          return { ...item, [field]: value };
        }
        return item;
      });
      saveSyncedState({ items: updatedItems });
    }

    // Delete item helper
    function deleteItem(id) {
      const updatedItems = state.items.filter(item => item.id !== id);
      saveSyncedState({ items: updatedItems });
    }

    // Initialization
    window.addEventListener('DOMContentLoaded', () => {
      initOwnerSelects();
      loadSyncedState();

      if (envId) {
        setInterval(loadSyncedState, 2000);
      }
    });

    window.addEventListener('resize', autoResizeTextareas);
  </script>
</body>
</html>
